-- Run-scoped graph protects tenant conclusions; only public source metadata stays reusable.
create table if not exists public.evidence_graph_nodes (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.research_runs(id) on delete cascade, node_type text not null, node_key text not null, label text not null, attributes jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), unique(run_id,node_type,node_key));
create table if not exists public.evidence_graph_edges (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.research_runs(id) on delete cascade, from_node_id uuid not null references public.evidence_graph_nodes(id) on delete cascade, to_node_id uuid not null references public.evidence_graph_nodes(id) on delete cascade, relation text not null, evidence_ids uuid[] not null default '{}', created_at timestamptz not null default now(), unique(run_id,from_node_id,to_node_id,relation));
create table if not exists public.evidence_clusters (id uuid primary key default gen_random_uuid(), run_id uuid not null references public.research_runs(id) on delete cascade, cluster_key text not null, cluster_type text not null, representative_claim text not null, supporting_evidence_ids uuid[] not null default '{}', contradicting_evidence_ids uuid[] not null default '{}', independent_source_count integer not null default 0, independent_domain_count integer not null default 0, tier_distribution jsonb not null default '{}'::jsonb, date_range jsonb not null default '{}'::jsonb, confidence numeric not null default 0, unresolved_disagreement boolean not null default false, created_at timestamptz not null default now(), unique(run_id,cluster_key));
create table if not exists public.evidence_confidence_results (run_id uuid primary key references public.research_runs(id) on delete cascade, band text not null check (band in ('High','Moderate','Low','Insufficient')), score numeric not null, reasons jsonb not null default '[]'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
alter table public.evidence_graph_nodes enable row level security; alter table public.evidence_graph_edges enable row level security; alter table public.evidence_clusters enable row level security; alter table public.evidence_confidence_results enable row level security;
